final class $$LocationsTableReferences
    extends BaseReferences<_$AppDatabase, $LocationsTable, Location> {
  $$LocationsTableReferences(super.$_db, super.$_table, super.$_typedResult);

  static $WorksTable _workIdTable(_$AppDatabase db) => db.works.createAlias(
    $_aliasNameGenerator(db.locations.workId, db.works.id),
  );

  $$WorksTableProcessedTableManager get workId {
    final $_column = $_itemColumn<String>('work_id')!;

    final manager = $$WorksTableTableManager(
      $_db,
      $_db.works,
    ).filter((f) => f.id.sqlEquals($_column));
    final item = $_typedResult.readTableOrNull(_workIdTable($_db));
    if (item == null) return manager;
    return ProcessedTableManager(
      manager.$state.copyWith(prefetchedData: [item]),
    );
  }

  static MultiTypedResultKey<$LocationCharactersTable, List<LocationCharacter>>
  _locationCharactersRefsTable(_$AppDatabase db) =>
      MultiTypedResultKey.fromTable(
        db.locationCharacters,
        aliasName: $_aliasNameGenerator(
          db.locations.id,
          db.locationCharacters.locationId,
        ),
      );

  $$LocationCharactersTableProcessedTableManager get locationCharactersRefs {
    final manager = $$LocationCharactersTableTableManager(
      $_db,
      $_db.locationCharacters,
    ).filter((f) => f.locationId.id.sqlEquals($_itemColumn<String>('id')!));

    final cache = $_typedResult.readTableOrNull(
      _locationCharactersRefsTable($_db),
    );
    return ProcessedTableManager(
      manager.$state.copyWith(prefetchedData: cache),
    );
  }
}

